-- ============================================================
-- ESRM KPI Monitoring - Create table + insert all 4452 records
-- Schema: mstr
-- ============================================================

DROP TABLE IF EXISTS mstr.esrm_kpi_monitoring CASCADE;

CREATE TABLE mstr.esrm_kpi_monitoring (
    case_id                         INTEGER,
    case_status                     VARCHAR(100),
    case_rating                     VARCHAR(100),
    entity_id                       VARCHAR(50),
    entity_name                     VARCHAR(200),
    client_domicile_country         VARCHAR(20),
    segment                         VARCHAR(100),
    sub_segment                     VARCHAR(200),
    cesra_rm_approver               VARCHAR(100),
    maker_name                      VARCHAR(100),
    isic_desc                       VARCHAR(200),
    sector_template                 VARCHAR(500),
    case_referred_to_esrm_hub       VARCHAR(10),
    case_referral_date              TIMESTAMP,
    case_review_date                TIMESTAMP,
    esrm_hub_name                   VARCHAR(100),
    review_time_in_business_days    INTEGER
);

-- ============================================================
-- INSERT all records
-- ============================================================


-- ============================================================
-- Indexes
-- ============================================================
CREATE INDEX idx_esrm_case_id ON mstr.esrm_kpi_monitoring (case_id);
CREATE INDEX idx_esrm_case_status ON mstr.esrm_kpi_monitoring (case_status);
CREATE INDEX idx_esrm_case_rating ON mstr.esrm_kpi_monitoring (case_rating);
CREATE INDEX idx_esrm_entity_id ON mstr.esrm_kpi_monitoring (entity_id);
CREATE INDEX idx_esrm_segment ON mstr.esrm_kpi_monitoring (segment);
CREATE INDEX idx_esrm_country ON mstr.esrm_kpi_monitoring (client_domicile_country);
CREATE INDEX idx_esrm_hub_referred ON mstr.esrm_kpi_monitoring (case_referred_to_esrm_hub);
